{
  "domain_analysis": {
    "business_context": "Order cancellation in a logistics/courier system. An order progresses through a lifecycle (placed → confirmed → picked up → in transit → out for delivery → delivered). Cancellation is a state transition that must respect the physical realities of package fulfillment — once a courier has possession of a package, cancellation has real-world operational consequences that differ from cancelling a digital record.",
    "bounded_context": "Order Management",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A request by a user to have a package picked up and delivered to a destination. Owns a lifecycle of discrete statuses." },
      { "term": "Cancellation", "definition": "A user-initiated request to abort an order. Not the same as a return or a refund — cancellation means the fulfillment process should stop." },
      { "term": "Order Status", "definition": "The current position of an order in its lifecycle. Determines what transitions (including cancellation) are legally and operationally valid." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted. Defined by business policy, constrained by physical reality." },
      { "term": "Cancellation Fee", "definition": "A charge applied when cancellation occurs after operational costs have been incurred (e.g., courier dispatched)." },
      { "term": "Order Owner", "definition": "The authenticated user who placed the order and is the only party authorized to request its cancellation." },
      { "term": "Fulfillment", "definition": "The operational process of picking up and delivering a package. Once fulfillment begins, cancellation has downstream consequences." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Only the order owner may cancel their own order.",
      "invariant": true,
      "invariant_justification": "Authorization invariant. Allowing any user to cancel another user's order would corrupt system integrity and violate basic access control.",
      "testable_assertion": "Given user A owns order X and user B does not, when user B attempts to cancel order X, then the system rejects the request with 403 Forbidden."
    },
    {
      "id": "BR-2",
      "rule": "An order that has reached a terminal status (delivered, already cancelled) cannot be cancelled.",
      "invariant": true,
      "invariant_justification": "State integrity. A delivered package physically exists at the destination — 'cancelling' it is meaningless. An already-cancelled order cannot transition again. Violating this corrupts the order lifecycle.",
      "testable_assertion": "Given an order with status 'delivered' or 'cancelled', when the owner requests cancellation, then the system rejects the request and returns an error indicating the order is not cancellable."
    },
    {
      "id": "BR-3",
      "rule": "Cancellation of an order must atomically update the order status to 'cancelled' and emit a domain event (OrderCancelled) so downstream systems (billing, courier dispatch, notifications) can react.",
      "invariant": true,
      "invariant_justification": "Data consistency. If the order is marked cancelled but no event is emitted, the courier may still attempt pickup/delivery, creating a ghost fulfillment. The status change and event must be atomic.",
      "testable_assertion": "Given a cancellable order, when the owner cancels it, then the order status is 'cancelled' AND an OrderCancelled event is published in the same transaction."
    },
    {
      "id": "BR-4",
      "rule": "Orders in statuses where operational work has begun (e.g., courier dispatched, in transit) may incur a cancellation fee.",
      "invariant": false,
      "invariant_justification": "Business policy. The fee structure, thresholds, and which statuses incur fees are policy decisions a VP could change. The existence of fees is not a physical constraint.",
      "testable_assertion": "Given an order with status 'in transit', when the owner cancels it, then a cancellation fee is calculated and applied to the order's financial record."
    },
    {
      "id": "BR-5",
      "rule": "When an order is cancelled, any assigned courier must be notified and unassigned from the delivery.",
      "invariant": true,
      "invariant_justification": "Operational integrity. A courier acting on a cancelled order wastes resources and creates a contradictory system state — the order says cancelled but a courier is still delivering it.",
      "testable_assertion": "Given an order with an assigned courier, when the order is cancelled, then the courier assignment is revoked and the courier receives a cancellation notification."
    },
    {
      "id": "BR-6",
      "rule": "The user must receive confirmation that their cancellation was processed, including any fees applied.",
      "invariant": false,
      "invariant_justification": "Business policy around user communication. The channel (email, push, in-app) and content are policy decisions, not system integrity constraints.",
      "testable_assertion": "Given a successful cancellation, when the system processes it, then the user receives a cancellation confirmation containing the order ID, cancellation timestamp, and any applicable fees."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An authenticated user viewing their own order with status 'placed' or 'confirmed' (no operational work begun)",
      "when": "The user requests cancellation of that order",
      "then": "The order status transitions to 'cancelled', an OrderCancelled event is emitted, no cancellation fee is applied, and the user receives a cancellation confirmation"
    },
    {
      "id": "AC-2",
      "given": "An authenticated user viewing their own order with status 'picked up' or 'in transit' (operational work in progress)",
      "when": "The user requests cancellation of that order",
      "then": "The order status transitions to 'cancelled', an OrderCancelled event is emitted, the assigned courier is notified and unassigned, any applicable cancellation fee is calculated and communicated to the user, and the user receives a cancellation confirmation including fee details"
    },
    {
      "id": "AC-3",
      "given": "An authenticated user viewing their own order with status 'delivered'",
      "when": "The user requests cancellation",
      "then": "The system rejects the request with a clear message: 'This order has been delivered and cannot be cancelled. Please initiate a return instead.' The order status remains 'delivered'."
    },
    {
      "id": "AC-4",
      "given": "An authenticated user viewing their own order with status 'cancelled'",
      "when": "The user requests cancellation again",
      "then": "The system rejects the request with a clear message: 'This order is already cancelled.' The order status remains 'cancelled'. No duplicate OrderCancelled event is emitted."
    },
    {
      "id": "AC-5",
      "given": "An authenticated user attempting to cancel an order they do not own",
      "when": "The cancellation request is submitted",
      "then": "The system rejects the request with 403 Forbidden. No state change occurs. The actual order owner is not notified of the attempt."
    },
    {
      "id": "AC-6",
      "given": "An authenticated user cancels an order while a courier is en route to pickup",
      "when": "The cancellation is processed",
      "then": "The courier receives a real-time notification to abort the pickup, the courier is unassigned, and the courier's availability is restored for new assignments"
    },
    {
      "id": "AC-7",
      "given": "Two concurrent cancellation requests for the same order (e.g., user double-clicks)",
      "when": "Both requests reach the system",
      "then": "Exactly one cancellation succeeds and one is rejected as 'already cancelled'. Only one OrderCancelled event is emitted. No duplicate fees are applied."
    },
    {
      "id": "AC-8",
      "given": "An order with status 'out for delivery' (courier is actively delivering to recipient)",
      "when": "The user requests cancellation",
      "then": "The system rejects the request with a message: 'This order is out for delivery and can no longer be cancelled. Please refuse delivery or initiate a return.' The order status remains unchanged."
    }
  ],

  "edge_cases": [
    {
      "scenario": "Concurrent status change — user cancels while the system is transitioning the order to 'in transit'",
      "expected_behavior": "The system must use optimistic locking or equivalent to prevent a race condition. One operation wins. If cancellation wins, the transit transition is rejected. If transit wins, the cancellation must be re-evaluated against the new status."
    },
    {
      "scenario": "User cancels immediately after order is placed but before payment is fully captured",
      "expected_behavior": "Cancellation succeeds. Any pending payment authorization must be voided, not captured. No charge to the user."
    },
    {
      "scenario": "Network failure after cancellation is persisted but before the OrderCancelled event is delivered to downstream systems",
      "expected_behavior": "The system must guarantee eventual delivery of the OrderCancelled event (outbox pattern or equivalent). The courier must not continue fulfilling a cancelled order due to a missed event."
    },
    {
      "scenario": "Cancellation request for a non-existent order ID",
      "expected_behavior": "Return 404 Not Found. Do not leak information about whether the order exists for another user."
    },
    {
      "scenario": "Cancellation of an order containing perishable or hazardous goods already in transit",
      "expected_behavior": "Cancellation may still be allowed but must trigger special handling procedures — perishable goods may need to be rerouted to a return facility, not simply abandoned. This is a policy-dependent edge case."
    },
    {
      "scenario": "Partial fulfillment — order has multiple packages, some picked up and some not",
      "expected_behavior": "Cancellation should apply to the entire order. Packages already in transit must be recalled or rerouted. The cancellation fee should reflect the operational cost actually incurred."
    },
    {
      "scenario": "User cancels and immediately places a new identical order",
      "expected_behavior": "These are two independent orders. The cancellation of the first must complete fully (including courier unassignment) before the same courier could be assigned to the new order, to prevent confusion."
    },
    {
      "scenario": "Unauthenticated request to cancel an order",
      "expected_behavior": "Return 401 Unauthorized. No order information is disclosed."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly impacts revenue — a cancelled order generates no delivery fee. Cancellation fees partially offset operational costs incurred (courier dispatch, fuel, time). Without proper cancellation fee logic, late cancellations become a cost center. Refund processing for prepaid orders has cash flow implications.",
    "operational": "Every cancellation after courier dispatch wastes courier time and fuel. High cancellation rates in-transit degrade courier utilization and route efficiency. The courier notification system must be real-time to minimize wasted effort. Proper cancellation also frees up courier capacity for other deliveries.",
    "user": "Cancellation is a trust feature — users expect to be able to change their mind. A smooth cancellation experience increases platform trust and repeat usage. However, unclear cancellation policies (hidden fees, confusing status restrictions) erode trust. Users must always know WHY a cancellation was rejected.",
    "risk": "Race conditions between cancellation and status transitions could lead to ghost deliveries (cancelled order still delivered) or lost packages. Duplicate event emission could trigger double refunds. Lack of idempotency on cancellation requests could corrupt financial records.",
    "stakeholders_affected": [
      { "group": "End Users (Order Owners)", "impact": "Directly affected — this is their feature. Must be intuitive, fast, and transparent about fees and restrictions." },
      { "group": "Couriers", "impact": "Cancelled orders mid-route waste their time and earnings. Must receive timely notifications to minimize impact. Courier compensation policy for cancelled-in-transit orders needs to be defined." },
      { "group": "Finance/Billing", "impact": "Must handle refunds for prepaid orders, cancellation fee calculation, and revenue reconciliation for cancelled orders." },
      { "group": "Customer Support", "impact": "Will handle disputes about cancellation fees and edge cases where users feel they should have been allowed to cancel. Clear system messaging reduces support volume." },
      { "group": "Operations/Dispatch", "impact": "Must react to OrderCancelled events to re-optimize courier routes and reassign freed-up couriers." }
    ]
  },

  "confidence": {
    "level": 42,
    "reasoning": "The spec is a single sentence: 'Users should be able to cancel their order.' This provides no information about the order lifecycle states, cancellation fee policy, refund policy, which statuses are cancellable, multi-package order handling, or courier compensation. Every business rule and acceptance criterion above is inferred from general logistics domain knowledge, not from an actual spec. Multiple critical policy decisions remain undefined.",
    "high_confidence_areas": [
      "Terminal statuses (delivered, cancelled) cannot be cancelled — this is a physical/logical invariant",
      "Only the order owner can cancel — fundamental authorization rule",
      "Courier must be notified on cancellation — operational necessity",
      "Cancellation must be atomic with event emission — data consistency requirement"
    ],
    "low_confidence_areas": [
      "Exact set of cancellable statuses — is 'out for delivery' cancellable or not? Policy decision.",
      "Cancellation fee structure — amounts, which statuses trigger fees, caps",
      "Refund policy for prepaid orders — full refund, partial, timeline",
      "Whether partial order cancellation is supported",
      "Courier compensation for cancelled-in-transit orders",
      "Whether admin/support staff can also cancel orders on behalf of users"
    ],
    "assumptions": [
      "The order lifecycle follows: placed → confirmed → picked up → in transit → out for delivery → delivered",
      "Orders can also reach a 'cancelled' terminal state from eligible intermediate states",
      "Cancellation fees exist as a concept but their structure is policy-defined",
      "The system uses event-driven architecture for cross-service communication",
      "Only the order owner (not admin or support) is in scope for this feature",
      "'Out for delivery' is too late to cancel — but this is an assumption, not confirmed"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order statuses are cancellable. The boundary between 'cancellable' and 'too late to cancel' is a critical business decision — e.g., can a user cancel when the courier is already en route to pickup? When the package is in transit? Out for delivery?",
      "affected_stakeholders": ["End Users", "Couriers", "Operations"],
      "options": [
        "A) Allow cancellation up to 'picked up' only — simplest, least courier disruption",
        "B) Allow cancellation up to 'in transit' with a fee — balanced approach",
        "C) Allow cancellation at any non-terminal status with escalating fees — most user-friendly but operationally complex"
      ],
      "recommendation": "Option B — it balances user flexibility with operational reality. 'Out for delivery' is too late operationally."
    },
    {
      "type": "missing_context",
      "description": "No refund policy is specified. When a prepaid order is cancelled, the system must know: full refund? Partial refund minus fee? Refund to original payment method or credit? Timeline for refund processing?",
      "affected_stakeholders": ["End Users", "Finance/Billing", "Customer Support"],
      "options": [
        "A) Full refund minus any cancellation fee, to original payment method, within 5-10 business days",
        "B) Refund as platform credit (instant) with option to withdraw",
        "C) Defer to existing refund policy if one exists"
      ],
      "recommendation": "Option C if a refund policy exists. Otherwise Option A — it matches industry standard expectations."
    },
    {
      "type": "missing_context",
      "description": "No mention of courier compensation when an in-progress delivery is cancelled. If couriers are not compensated for wasted trips, it creates a fairness and retention problem.",
      "affected_stakeholders": ["Couriers", "Finance/Billing", "Operations"],
      "options": [
        "A) Pay courier a flat cancellation fee for wasted trip",
        "B) Pay courier based on distance already traveled",
        "C) No courier compensation — cancellation fee from user covers operational cost"
      ],
      "recommendation": "Option A — flat fee is simplest to implement and fair to couriers. Funded by the user's cancellation fee."
    },
    {
      "type": "ambiguity",
      "description": "Scope of 'user' is undefined. Does this feature cover only end-user self-service cancellation, or also admin/support-initiated cancellation on behalf of users? These have different authorization rules and audit requirements.",
      "affected_stakeholders": ["End Users", "Customer Support", "Engineering"],
      "options": [
        "A) Self-service only — admin cancellation is a separate feature",
        "B) Both self-service and admin in same feature with role-based access"
      ],
      "recommendation": "Option A — keep scope tight. Admin cancellation has different business rules (no fee, different audit trail) and should be a separate feature."
    }
  ],

  "rejection_reasons": []
}

